py-syntax.mistake:
# ❌ Wrong — inconsistent indentation
if 5 > 2:
 print("Yes")

# ✅ Correct
if 5 > 2:
    print("Yes")

py-ops.mistake:
# ❌ Wrong — using = instead of == in a condition
if x = 5:
    print("Yes")

# ✅ Correct
if x == 5:
    print("Yes")

py-cond.example:
score = 75
if score >= 90:
    print("Excellent")
elif score >= 70:
    print("Good job")
else:
    print("Keep practicing")

py-cond.mistake:
# ❌ Wrong — separate if statements instead of elif
if x > 10:
    print("Big")
if x > 5:
    print("Medium")

# ✅ Correct
if x > 10:
    print("Big")
elif x > 5:
    print("Medium")
